SELECT
*
FROM FILE_SERVER_DOCUMENT
WHERE VALID = '1'

    AND link_id = #{linkId}

And (

    type = #{type}


    OR type = CONCAT('bapOffice__',#{type})


    OR type = CONCAT('bapTemplate__',#{type})

)

    AND propertyCode = #{propertyCode}

AND (
fileType = 'office' OR fileType = 'attachment' OR fileType IS NULL
)
ORDER BY create_time ASC

